#include<bits/stdc++.h>
#define id(x,y) ((x-1)*n+y)
using namespace std;
int n;
int a[210][210],match[40010],b[40010];
int dx[8]={-1,-2,1,2,-1,-2,1,2};
int dy[8]={-2,-1,-2,-1,2,1,2,1};
vector<int> mp[40010];
bool vis[40010];
int dfs(int x)
{
    for(int i:mp[x])
    {
        if(vis[i])
        {
            continue;
        }
        vis[i]=true;
        if(match[i]==0||dfs(match[i]))
        {
            match[i]=x;
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%d",&n);
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            char ch;
            cin>>ch;
            ans+=1-(ch-'0');
            b[id(i,j)]=1-(ch-'0');
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)if((i+j)%2==1)
        {
            for(int k=0;k<8;k++)
            {
                int x=i+dx[k],y=j+dy[k];
                if(x>=1&&x<=n&&y>=1&&y<=n&&b[id(i,j)]&&b[id(x,y)])
                {
                    mp[id(i,j)].push_back(id(x,y));
                }
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(b[id(i,j)]&&(i+j)%2==1)
            {
                memset(vis,0,sizeof(vis));
                ans-=dfs(id(i,j));
            }
        }
    }
    printf("%d",ans);
    return 0;
}
